144→        // Get the user according to the username (email area code + mobile phone), if the username cannot be queried, an exception will be thrown automatically
145→        UserEntity user = iUserService.getByUsername(loginRo.getAreaCode(), loginRo.getUsername());
146→        checkAllowLogin(user);
147→        // Record the wrong keys of the user password, and lock them for 20 minutes each time
148→        String errorInputPwdCountKey = ERROR_PWD_NUM_DIR + user.getId();
149→        int errorPwdCount = 0;
150→        // Determine whether you have entered the wrong password more than five times in a row
151→        if (BooleanUtil.isTrue(redisTemplate.hasKey(errorInputPwdCountKey))) {
152→            // There is a record of the number of wrong passwords, and calculate whether it is greater than 5 times
153→            BoundValueOperations<String, Object> opts = redisTemplate.boundValueOps(errorInputPwdCountKey);
154→            Object value = opts.get();
155→            if (!Objects.isNull(value)) {
156→                errorPwdCount = Integer.parseInt(value.toString());
157→                ExceptionUtil.isTrue(errorPwdCount < 5, LOGIN_OFTEN);
158→            }
159→        }
160→        // Check if the passwords match
161→        if (!passwordService.matches(loginRo.getCredential(), user.getPassword())) {
162→            // Record the number of wrong passwords entered, and the account will be locked for 20 minutes if the wrong password is entered more than five times in a row
163→            BoundValueOperations<String, Object> opts = redisTemplate.boundValueOps(errorInputPwdCountKey);
164→            opts.set(errorPwdCount + 1, 20, TimeUnit.MINUTES);
165→            throw new BusinessException(USERNAME_OR_PASSWORD_ERROR);
166→        }
167→        // Update last login time
168→        iUserService.updateLoginTime(user.getId());
