273→    public String authorize(String jumpBackUrl) {
274→        String uuid = IdUtil.simpleUUID().toString();
275→        String redisKey = StrUtil.format(AUTHORIZED_JUMP_URL, uuid);
276→        redisTemplate.opsForValue().set(redisKey, jumpBackUrl, 2, TimeUnit.HOURS);
277→        final String uri = "/api/v1/auth/callback";
278→        String redirectUrl = OACoreHost + "/oauth/authorize?response_type=code" +
279→                "&client_id=" + clientId +
280→                "&redirect_uri=" + apittableHost + uri +
281→                "&state=" + uuid;
282→        return redirectUrl;
283→    }
