285→    @Override
286→    public String registerAndLogin(String code, String state, ClientOriginInfo origin) {
287→        final String grantType = "authorization_code";
288→        // redirectUri 与authorize中&redirect_uri保持一致
289→        final String uri = "/api/v1/auth/callback";
290→        OAAuthTokenResp authInfo = oaAuthService.token(OAAuthTokenRequest.builder()
291→                .code(code)
292→                .clientId(clientId)
293→                .clientSecret(clientSecret)
294→                .grantType(grantType)
295→                .redirectUri(apittableHost + uri)
296→                .build());
297→        if (authInfo.getUserInfo() == null) {
298→            log.error("token return error, authInfo:{}", authInfo);
299→            throw new BusinessException("获取授权信息失败");
300→        }
301→        OAUserInfo userInfo = authInfo.getUserInfo();
302→        String accessToken = authInfo.getAccessToken();
303→        String accessKey = StrUtil.format(ACCESS_TOKEN_EMAIL, userInfo.getEmail());
304→        // 设置accessToken 有效期30m， 用于登录验证
305→        redisTemplate.opsForValue().set(accessKey, accessToken, authInfo.getExpiresIn(), TimeUnit.SECONDS);
306→        // 授权人已存在账户， 登录
307→        LoginRo data = new LoginRo();
308→        data.setUsername(userInfo.getEmail());
309→        data.setType(LoginType.SSO_AUTH);
310→        boolean exist = iUserService.checkByEmail(userInfo.getEmail());
311→        if (exist) {
312→            this.login(data, origin);
313→        } else {
314→            // 注册账户再登录
315→            this.register(userInfo.getEmail(), null, userInfo.getNickname());
316→            this.login(data, origin);
317→        }
318→        String redisKey = StrUtil.format(AUTHORIZED_JUMP_URL, state);
