323→    @Override
324→    public void login(LoginRo data, ClientOriginInfo origin) {
325→        // Login Type Routing
326→        Map<LoginType, Function<LoginRo, Long>> loginActionFunc =
327→                new HashMap<>();
328→        // password login
329→        loginActionFunc.put(LoginType.PASSWORD, loginRo -> {
330→            // Password login requires human-machine authentication
331→            humanVerificationServiceFacade.verifyNonRobot(
332→                    new NonRobotMetadata(loginRo.getData()));
333→            // Login processing
334→            Long userId = this.loginUsingPassword(loginRo);
335→            // event point - password login
336→            eventBusFacade.onEvent(
337→                    new UserLoginEvent(userId, LoginType.PASSWORD, false,
338→                            origin));
339→            return userId;
340→        });
341→        // SMS verification code login
342→        loginActionFunc.put(LoginType.SMS_CODE, loginRo -> {
343→            UserLoginDTO result = this.loginUsingSmsCode(loginRo);
344→            // sensors point - Login or Register
345→            if (Boolean.TRUE.equals(result.getIsSignUp())) {
346→                eventBusFacade.onEvent(
347→                        new UserLoginEvent(result.getUserId(), LoginType.SMS_CODE,
348→                                true, origin));
349→            } else {
350→                eventBusFacade.onEvent(
351→                        new UserLoginEvent(result.getUserId(), LoginType.SMS_CODE,
352→                                false, origin));
353→            }
354→            return result.getUserId();
355→        });
356→        // Email verification code login
357→        loginActionFunc.put(LoginType.EMAIL_CODE, loginRo -> {
358→            UserLoginDTO result = this.loginUsingEmailCode(loginRo);
359→            // sensors point - Login or Register
360→            if (Boolean.TRUE.equals(result.getIsSignUp())) {
361→                eventBusFacade.onEvent(
362→                        new UserLoginEvent(result.getUserId(), LoginType.EMAIL_CODE,
363→                                true, origin));
364→            } else {
365→                eventBusFacade.onEvent(
366→                        new UserLoginEvent(result.getUserId(), LoginType.EMAIL_CODE,
367→                                false, origin));
368→            }
369→            return result.getUserId();
370→        });
371→        // SSO login (private user use)
372→        loginActionFunc.put(LoginType.SSO_AUTH, loginRo -> {
373→            UserAuth userAuth = authServiceFacade.ssoLogin(
374→                    new AuthParam(data.getUsername(), data.getCredential()));
375→            // Update last login time
376→            iUserService.updateLoginTime(userAuth.getUserId());
377→            return userAuth != null ? userAuth.getUserId() : null;
378→        });
379→        // Handling login logic
380→        Long userId = loginActionFunc.get(data.getType()).apply(data);
381→        // Banned account verification
382→        blackListServiceFacade.checkUser(userId);
383→        String nickname = iUserService.getNicknameByUserId(userId);
384→        // save session
385→        SessionContext.setUserId(userId, nickname);
