388→    @Override
389→    public LoginValidateResponse validateAndLogin(OdLoginRo loginRo) {
390→
391→        log.info("收到登录验证请求，用户名: {}", loginRo.getUsername());
392→
393→        try {
394→            // 获取请求参数
395→            String username = loginRo.getUsername();
396→            String password = loginRo.getPassword();
397→
398→            // 参数验证
399→            if (username.trim().isEmpty()) {
400→                log.warn( "用户名或密码错误");
401→                return new LoginValidateResponse(0L, "用户名或密码错误");
402→            }
403→
404→            if (password.trim().isEmpty()) {
405→                log.warn( "用户名或密码错误");
406→                return new LoginValidateResponse(0L, "用户名或密码错误");
407→            }
408→
409→            UserEntity existedUser = userMapper.selectByEmail(username);
410→            if (existedUser == null){
411→                log.warn( "用户名或密码错误");
412→                return new LoginValidateResponse(0L, "用户名或密码错误");
413→            }
414→            else{
415→                if (!passwordService.matches(password, existedUser.getPassword())){
416→                    log.warn( "用户名或密码错误");
417→                    return new LoginValidateResponse(0L, "用户名或密码错误");
418→                }
419→            }
420→
421→            // 调用业务服务验证用户
422→            Long userId = existedUser.getId();
423→
424→            if (userId != null && userId > 0) {
425→                log.info("用户 {} 登录验证成功，用户ID: {}", username, userId);
426→                return new LoginValidateResponse(userId, "登录验证成功");
427→            } else {
428→                // 验证失败
429→                log.warn("用户 {} 登录验证失败", username);
430→                return new LoginValidateResponse(0L, "登录验证失败");
431→            }
432→        } catch (Exception e) {
433→            log.error("处理登录验证请求时发生错误", e);
434→            return new LoginValidateResponse(0L, "系统内部错误");
435→        }
436→    }
