import com.apitable.core.exception.BusinessException;
import com.apitable.core.util.ExceptionUtil;
import com.apitable.interfaces.auth.facade.AuthServiceFacade;
import com.apitable.interfaces.auth.model.AuthParam;
import com.apitable.interfaces.auth.model.UserAuth;
import com.apitable.interfaces.eventbus.facade.EventBusFacade;
import com.apitable.interfaces.eventbus.model.UserLoginEvent;
import com.apitable.interfaces.security.facade.BlackListServiceFacade;
import com.apitable.interfaces.security.facade.HumanVerificationServiceFacade;
import com.apitable.interfaces.security.model.NonRobotMetadata;
import com.apitable.interfaces.user.facade.UserLinkServiceFacade;
import com.apitable.interfaces.user.model.UserLinkRequest;
import com.apitable.organization.dto.MemberDTO;
import com.apitable.organization.service.IMemberService;
import com.apitable.shared.cache.bean.SocialAuthInfo;
import com.apitable.shared.cache.service.SocialAuthInfoCacheService;
import com.apitable.shared.captcha.*;
import com.apitable.shared.context.SessionContext;
import com.apitable.shared.security.PasswordService;
import com.apitable.shared.util.information.ClientOriginInfo;
import com.apitable.thrid.dto.OAUserInfo;
import com.apitable.thrid.req.OAAuthTokenRequest;
import com.apitable.thrid.feign.OAAuthService;
import com.apitable.thrid.resp.OAAuthTokenResp;
import com.apitable.user.entity.UserEntity;
import com.apitable.user.enums.UserException;
import com.apitable.user.mapper.UserMapper;
import com.apitable.user.service.IUserService;
import com.apitable.workspace.util.IpUtil;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.data.redis.core.BoundValueOperations;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import javax.annotation.Resource;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.concurrent.TimeUnit;
import java.util.function.Function;
import java.util.stream.Collectors;

import static com.apitable.core.constants.RedisConstants.*;
import static com.apitable.user.enums.UserException.*;

/**
 * Authorization-related service interface implementation
 */
@Service
@Slf4j
public class AuthServiceImpl implements IAuthService {

    @Resource
    private RedisTemplate<String, Object> redisTemplate;

    @Resource
    private IUserService iUserService;

    @Resource
    private IMemberService iMemberService;

    @Resource
    private SocialAuthInfoCacheService socialAuthInfoCacheService;

    @Resource
    private UserLinkServiceFacade userLinkServiceFacade;

    @Resource
    private PasswordService passwordService;
    @Resource
    private OAAuthService oaAuthService;

    @Resource
    private EventBusFacade eventBusFacade;
    @Resource
    private AuthServiceFacade authServiceFacade;
    @Resource
    private BlackListServiceFacade blackListServiceFacade;
    @Resource
    private HumanVerificationServiceFacade humanVerificationServiceFacade;

    @Value("${oa.core.client-id}")
    private String clientId;

    @Value("${oa.core.client-secret}")
    private String clientSecret;

    @Value("${apitable.host}")
    private String apittableHost;

    @Value("${oa.core.host}")
    private String OACoreHost;
    @Resource
    private UserMapper userMapper;

    @Override
    public Long register(final String username, final String password, final String nickname) {
        // Check email format and if exists
        ExceptionUtil.isTrue(Validator.isEmail(username), REGISTER_EMAIL_ERROR);
        boolean exist = iUserService.checkByEmail(username);
        ExceptionUtil.isFalse(exist, REGISTER_EMAIL_HAS_EXIST);
        // Register User
        return this.registerUserUsingEmail(username, password, nickname);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public Long loginUsingPassword(LoginRo loginRo) {
        // Get the user according to the username (email area code + mobile phone), if the username cannot be queried, an exception will be thrown automatically
        UserEntity user = iUserService.getByUsername(loginRo.getAreaCode(), loginRo.getUsername());
        checkAllowLogin(user);
        // Record the wrong keys of the user password, and lock them for 20 minutes each time
        String errorInputPwdCountKey = ERROR_PWD_NUM_DIR + user.getId();
        int errorPwdCount = 0;
        // Determine whether you have entered the wrong password more than five times in a row
        if (BooleanUtil.isTrue(redisTemplate.hasKey(errorInputPwdCountKey))) {
            // There is a record of the number of wrong passwords, and calculate whether it is greater than 5 times
            BoundValueOperations<String, Object> opts = redisTemplate.boundValueOps(errorInputPwdCountKey);
            Object value = opts.get();
            if (!Objects.isNull(value)) {
                errorPwdCount = Integer.parseInt(value.toString());
                ExceptionUtil.isTrue(errorPwdCount < 5, LOGIN_OFTEN);
            }
        }
        // Check if the passwords match
        if (!passwordService.matches(loginRo.getCredential(), user.getPassword())) {
            // Record the number of wrong passwords entered, and the account will be locked for 20 minutes if the wrong password is entered more than five times in a row
            BoundValueOperations<String, Object> opts = redisTemplate.boundValueOps(errorInputPwdCountKey);
            opts.set(errorPwdCount + 1, 20, TimeUnit.MINUTES);
            throw new BusinessException(USERNAME_OR_PASSWORD_ERROR);
        }
        // Update last login time
        iUserService.updateLoginTime(user.getId());
        // Successful login, clear the number of wrong password input
        redisTemplate.delete(errorInputPwdCountKey);
        return user.getId();
    }

    /**
     * 检查是否允许登录
     * @param user
     */
    public static void checkAllowLogin(UserEntity user) {
        if (user.getStatus() != 0) {
            //llog.info("账号状态异常 userId:{}, status:{}", user.getId(), user.getStatus());
            throw new BusinessException(UserException.STATUS_EXCEPTION);
        }
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public UserLoginDTO loginUsingSmsCode(LoginRo loginRo) {
        UserLoginDTO result = new UserLoginDTO();
        // Log in by SMS verification code, if it does not exist, it will automatically register
        String areaCode = StrUtil.trim(loginRo.getAreaCode());
        ExceptionUtil.isNotBlank(areaCode, MOBILE_EMPTY);
        String mobile = StrUtil.trim(loginRo.getUsername());
        ExceptionUtil.isNotBlank(mobile, MOBILE_EMPTY);
        String mobileValidCode = StrUtil.trim(loginRo.getCredential());
        ExceptionUtil.isNotBlank(mobileValidCode, ActionException.CODE_EMPTY);
        // Verify mobile phone verification code
        ValidateCodeProcessor processor = ValidateCodeProcessorManage.me().findValidateCodeProcessor(ValidateCodeType.SMS);
        ValidateTarget target = ValidateTarget.create(loginRo.getUsername(), loginRo.getAreaCode());
        processor.validate(target, mobileValidCode, false, CodeValidateScope.LOGIN);
        // Get user authorization information from cache
        SocialAuthInfo authInfo = socialAuthInfoCacheService.getAuthInfoFromCache(loginRo.getToken());
        // Whether to bind the mobile phone number after the third-party scan code login operation
        boolean socialLogin = authInfo != null && StrUtil.isNotBlank(authInfo.getUnionId());
        if (socialLogin) {
            userLinkServiceFacade.wrapperSocialAuthInfo(authInfo);
        }
        Long userId = iUserService.getUserIdByMobile(mobile);
        if (ObjectUtil.isNotNull(userId)) {
            // Update last login time
            iUserService.updateLoginTime(userId);
            // Query whether there is a space member corresponding to a mobile phone number
            List<MemberDTO> inactiveMembers = iMemberService.getInactiveMemberDtoByMobile(mobile);
            iMemberService.activeIfExistInvitationSpace(userId, inactiveMembers.stream().map(MemberDTO::getId).collect(Collectors.toList()));
        } else {
            // registered a new user
            String nickName = socialLogin ? authInfo.getNickName() : null;
            String avatar = socialLogin ? authInfo.getAvatar() : null;
            userId = registerUserUsingMobilePhone(areaCode, mobile, nickName, avatar);
            if (StrUtil.isNotEmpty(loginRo.getSpaceId())) {
                // Cache, used to invite users to give away attachment capacity
                this.handleCache(userId, loginRo.getSpaceId());
            }
            result.setIsSignUp(true);
        }
        // If it is a third-party application that binds the account after scanning the code to log in
        if (socialLogin) {
            userLinkServiceFacade.createUserLink(new UserLinkRequest(userId, authInfo));
        }
        // delete verification code
        processor.delCode(target.getRealTarget(), CodeValidateScope.LOGIN);
        // Immediately delete third-party authorization information from the cache
        removeInviteTokenFromCache(loginRo.getToken());
        result.setUserId(userId);
        return result;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public UserLoginDTO loginUsingEmailCode(LoginRo loginRo) {
        UserLoginDTO result = new UserLoginDTO();
        String email = loginRo.getUsername();
        String emailValidCode = StrUtil.trim(loginRo.getCredential());
        // Check parameters
        ExceptionUtil.isTrue(Validator.isEmail(email), REGISTER_EMAIL_ERROR);
        ExceptionUtil.isNotBlank(emailValidCode, ActionException.CODE_EMPTY);
        // Verify verification code
        ValidateCodeProcessor processor = ValidateCodeProcessorManage.me().findValidateCodeProcessor(ValidateCodeType.EMAIL);
        processor.validate(ValidateTarget.create(email), emailValidCode, false, CodeValidateScope.REGISTER_EMAIL);
        // determine whether there is
        Long userId = iUserService.getUserIdByEmail(email);
        if (userId != null) {
            // Update last login time
            iUserService.updateLoginTime(userId);
            // Query whether there is a space member corresponding to the mailbox, only new registration will have this operation
            List<MemberDTO> inactiveMembers = iMemberService.getInactiveMemberDtoByEmail(email);
            iMemberService.activeIfExistInvitationSpace(userId, inactiveMembers.stream().map(MemberDTO::getId).collect(Collectors.toList()));
        } else {
            // Email automatic registration users do not provide third-party scan code login binding
            userId = registerUserUsingEmail(email, null, null);
            if (StrUtil.isNotEmpty(loginRo.getSpaceId())) {
                // Cache, used to invite users to give away attachment capacity
                this.handleCache(userId, loginRo.getSpaceId());
            }
            result.setIsSignUp(true);
        }
        // delete verification code
        processor.delCode(email, CodeValidateScope.LOGIN);
        result.setUserId(userId);
        return result;
    }

    @Override
    public String authorize(String jumpBackUrl) {
        String uuid = IdUtil.simpleUUID().toString();
        String redisKey = StrUtil.format(AUTHORIZED_JUMP_URL, uuid);
        redisTemplate.opsForValue().set(redisKey, jumpBackUrl, 2, TimeUnit.HOURS);
        final String uri = "/api/v1/auth/callback";
        String redirectUrl = OACoreHost + "/oauth/authorize?response_type=code" +
                "&client_id=" + clientId +
                "&redirect_uri=" + apittableHost + uri +
                "&state=" + uuid;
        return redirectUrl;
    }

    @Override
    public String registerAndLogin(String code, String state, ClientOriginInfo origin) {
        final String grantType = "authorization_code";
        // redirectUri 与authorize中&redirect_uri保持一致
        final String uri = "/api/v1/auth/callback";
        OAAuthTokenResp authInfo = oaAuthService.token(OAAuthTokenRequest.builder()
                .code(code)
                .clientId(clientId)
                .clientSecret(clientSecret)
                .grantType(grantType)
                .redirectUri(apittableHost + uri)
                .build());
        if (authInfo.getUserInfo() == null) {
            log.error("token return error, authInfo:{}", authInfo);
            throw new BusinessException("获取授权信息失败");
        }
        OAUserInfo userInfo = authInfo.getUserInfo();
        String accessToken = authInfo.getAccessToken();
        String accessKey = StrUtil.format(ACCESS_TOKEN_EMAIL, userInfo.getEmail());
        // 设置accessToken 有效期30m， 用于登录验证
        redisTemplate.opsForValue().set(accessKey, accessToken, authInfo.getExpiresIn(), TimeUnit.SECONDS);
        // 授权人已存在账户， 登录
        LoginRo data = new LoginRo();
        data.setUsername(userInfo.getEmail());
        data.setType(LoginType.SSO_AUTH);
        boolean exist = iUserService.checkByEmail(userInfo.getEmail());
        if (exist) {
            this.login(data, origin);
        } else {
            // 注册账户再登录
            this.register(userInfo.getEmail(), null, userInfo.getNickname());
            this.login(data, origin);
        }
        String redisKey = StrUtil.format(AUTHORIZED_JUMP_URL, state);
        String jumpUrl = (String)redisTemplate.opsForValue().get(redisKey);
        return jumpUrl;
    }

    @Override
    public void login(LoginRo data, ClientOriginInfo origin) {
        // Login Type Routing
        Map<LoginType, Function<LoginRo, Long>> loginActionFunc =
                new HashMap<>();
        // password login
        loginActionFunc.put(LoginType.PASSWORD, loginRo -> {
            // Password login requires human-machine authentication
            humanVerificationServiceFacade.verifyNonRobot(
                    new NonRobotMetadata(loginRo.getData()));
            // Login processing
            Long userId = this.loginUsingPassword(loginRo);
            // event point - password login
            eventBusFacade.onEvent(
                    new UserLoginEvent(userId, LoginType.PASSWORD, false,
                            origin));
            return userId;
        });
        // SMS verification code login
        loginActionFunc.put(LoginType.SMS_CODE, loginRo -> {
            UserLoginDTO result = this.loginUsingSmsCode(loginRo);
            // sensors point - Login or Register
            if (Boolean.TRUE.equals(result.getIsSignUp())) {
                eventBusFacade.onEvent(
                        new UserLoginEvent(result.getUserId(), LoginType.SMS_CODE,
                                true, origin));
            } else {
                eventBusFacade.onEvent(
                        new UserLoginEvent(result.getUserId(), LoginType.SMS_CODE,
                                false, origin));
            }
            return result.getUserId();
        });
        // Email verification code login
        loginActionFunc.put(LoginType.EMAIL_CODE, loginRo -> {
            UserLoginDTO result = this.loginUsingEmailCode(loginRo);
            // sensors point - Login or Register
            if (Boolean.TRUE.equals(result.getIsSignUp())) {
                eventBusFacade.onEvent(
                        new UserLoginEvent(result.getUserId(), LoginType.EMAIL_CODE,
                                true, origin));
            } else {
                eventBusFacade.onEvent(
                        new UserLoginEvent(result.getUserId(), LoginType.EMAIL_CODE,
                                false, origin));
            }
            return result.getUserId();
        });
        // SSO login (private user use)
        loginActionFunc.put(LoginType.SSO_AUTH, loginRo -> {
            UserAuth userAuth = authServiceFacade.ssoLogin(
                    new AuthParam(data.getUsername(), data.getCredential()));
            // Update last login time
            iUserService.updateLoginTime(userAuth.getUserId());
            return userAuth != null ? userAuth.getUserId() : null;
        });
        // Handling login logic
        Long userId = loginActionFunc.get(data.getType()).apply(data);
        // Banned account verification
        blackListServiceFacade.checkUser(userId);
        String nickname = iUserService.getNicknameByUserId(userId);
        // save session
        SessionContext.setUserId(userId, nickname);
    }

    @Override
    public LoginValidateResponse validateAndLogin(OdLoginRo loginRo) {

        log.info("收到登录验证请求，用户名: {}", loginRo.getUsername());

        try {
            // 获取请求参数
            String username = loginRo.getUsername();
            String password = loginRo.getPassword();

            // 参数验证
            if (username.trim().isEmpty()) {
                log.warn( "用户名或密码错误");
                return new LoginValidateResponse(0L, "用户名或密码错误");
            }

            if (password.trim().isEmpty()) {
                log.warn( "用户名或密码错误");
                return new LoginValidateResponse(0L, "用户名或密码错误");
            }

            UserEntity existedUser = userMapper.selectByEmail(username);
            if (existedUser == null){
                log.warn( "用户名或密码错误");
                return new LoginValidateResponse(0L, "用户名或密码错误");
            }
            else{
                if (!passwordService.matches(password, existedUser.getPassword())){
                    log.warn( "用户名或密码错误");
                    return new LoginValidateResponse(0L, "用户名或密码错误");
                }
            }

            // 调用业务服务验证用户
            Long userId = existedUser.getId();

            if (userId != null && userId > 0) {
                log.info("用户 {} 登录验证成功，用户ID: {}", username, userId);
                return new LoginValidateResponse(userId, "登录验证成功");
            } else {
                // 验证失败
                log.warn("用户 {} 登录验证失败", username);
                return new LoginValidateResponse(0L, "登录验证失败");
            }
        } catch (Exception e) {
            log.error("处理登录验证请求时发生错误", e);
            return new LoginValidateResponse(0L, "系统内部错误");
        }
    }

    public Long registerUserUsingMobilePhone(String areaCode, String mobile, String nickName, String avatar) {
        // Create a new user based on the mobile phone number and activate the corresponding member
        UserEntity user = iUserService.createUserByMobilePhone(areaCode, mobile, nickName, avatar);
        // Query whether there is a space member corresponding to a mobile phone number
        List<MemberDTO> inactiveMembers = iMemberService.getInactiveMemberDtoByMobile(mobile);
        createOrActiveSpace(user, inactiveMembers.stream().map(MemberDTO::getId).collect(Collectors.toList()));
        return user.getId();
    }

    private Long registerUserUsingEmail(final String email, final String password, final String nickname) {
        // Create a new user based on the mailbox and activate the corresponding member
        UserEntity user = iUserService.createUserByEmail(email, password, nickname);
        // Query whether there is a space member corresponding to the mailbox, only new
        // registration will have this operation
        List<MemberDTO> inactiveMembers = iMemberService.getInactiveMemberDtoByEmail(email);
        createOrActiveSpace(user,
            inactiveMembers.stream().map(MemberDTO::getId).collect(Collectors.toList()));
        return user.getId();
    }

    private void createOrActiveSpace(UserEntity user, List<Long> memberIds) {
        if (memberIds.isEmpty()) {
            iUserService.initialDefaultSpaceForUser(user);
        } else {
            iMemberService.activeIfExistInvitationSpace(user.getId(), memberIds);
        }
    }

    private void removeInviteTokenFromCache(String token) {
        redisTemplate.delete(StrUtil.format(USER_AUTH_INFO_TOKEN, token));
    }

    private void handleCache(Long userId, String spaceId) {
        String key = getUserInvitedJoinSpaceKey(userId, spaceId);
        redisTemplate.opsForValue().set(key, userId, 5, TimeUnit.MINUTES);
    }

}

