import { useState } from "react"
import { createFileRoute } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Trash2, Copy, Key, Clock, Calendar } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { Switch } from "@/components/ui/switch"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { formatDateTime } from "@/lib/utils"
import {
  useTokenList,
  useCreateToken,
  useToggleToken,
  useDeleteToken,
  useAllCallLogs,
} from "@/hooks/use-admin-tokens"

export const Route = createFileRoute("/_layout/admin/tokens")({
  component: AdminTokensPage,
})

function AdminTokensPage() {
  const { t } = useTranslation()
  const [showCreate, setShowCreate] = useState(false)
  const [showDelete, setShowDelete] = useState<number | null>(null)
  const [newTokenName, setNewTokenName] = useState("")
  const [expiryOption, setExpiryOption] = useState("never")
  const [createdToken, setCreatedToken] = useState<string | null>(null)

  const { data: tokens = [], isLoading } = useTokenList()
  const { data: logs = [] } = useAllCallLogs()
  const createMutation = useCreateToken()
  const toggleMutation = useToggleToken()
  const deleteMutation = useDeleteToken()

  const expiryOptions = [
    { value: "never", label: t("token.neverExpire") },
    { value: "7", label: t("token.expiry7d") },
    { value: "30", label: t("token.expiry30d") },
    { value: "90", label: t("token.expiry90d") },
    { value: "365", label: t("token.expiry1y") },
  ]

  const calcExpiresAt = (option: string): string | null => {
    if (option === "never") return null
    const date = new Date()
    date.setDate(date.getDate() + Number(option))
    return date.toISOString()
  }

  const handleCreate = () => {
    if (!newTokenName.trim()) return
    createMutation.mutate(
      { name: newTokenName, expiresAt: calcExpiresAt(expiryOption) },
      {
        onSuccess: (data) => {
          setCreatedToken(data.token)
          setNewTokenName("")
          setExpiryOption("never")
          toast.success(t("token.createSuccess"))
        },
      },
    )
  }

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text)
    toast.success(t("token.copied"))
  }

  const handleDelete = (id: number) => {
    deleteMutation.mutate(id, {
      onSuccess: () => {
        setShowDelete(null)
        toast.success(t("token.deleteSuccess"))
      },
    })
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-semibold">{t("token.title")}</h1>
          <p className="mt-1 text-sm text-muted-foreground">{t("token.createDesc")}</p>
        </div>
        <Button onClick={() => { setShowCreate(true); setCreatedToken(null) }}>
          <Plus className="mr-2 h-4 w-4" />
          {t("token.create")}
        </Button>
      </div>

      <Tabs defaultValue="tokens">
        <TabsList>
          <TabsTrigger value="tokens">{t("token.tokenList")}</TabsTrigger>
          <TabsTrigger value="logs">{t("token.callLogs")}</TabsTrigger>
        </TabsList>

        <TabsContent value="tokens" className="mt-4">
          {isLoading ? (
            <div className="py-16 text-center text-muted-foreground">{t("common.loading")}</div>
          ) : tokens.length === 0 ? (
            <div className="flex flex-col items-center justify-center rounded-lg border border-dashed py-16">
              <Key className="mb-3 h-10 w-10 text-muted-foreground/50" />
              <p className="text-muted-foreground">{t("common.noData")}</p>
              <Button variant="outline" size="sm" className="mt-4" onClick={() => { setShowCreate(true); setCreatedToken(null) }}>
                <Plus className="mr-1 h-4 w-4" />
                {t("token.create")}
              </Button>
            </div>
          ) : (
            <div className="grid gap-3">
              {tokens.map((token) => (
                <div
                  key={token.id}
                  className="flex items-center justify-between rounded-lg border bg-card p-4 transition-colors hover:bg-accent/30"
                >
                  <div className="flex-1 space-y-1">
                    <div className="flex items-center gap-3">
                      <span className="font-medium">{token.name}</span>
                      <Badge variant={token.enabled ? "default" : "secondary"} className="text-xs">
                        {token.enabled ? t("token.enabled") : t("token.disabled")}
                      </Badge>
                    </div>
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      <span className="font-mono">{token.token}</span>
                      <span className="flex items-center gap-1">
                        <Calendar className="h-3 w-3" />
                        {formatDateTime(new Date(token.createdAt))}
                      </span>
                      {token.expiresAt && (
                        <span className="flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          {t("token.expiresAt")}: {formatDateTime(new Date(token.expiresAt))}
                        </span>
                      )}
                      {!token.expiresAt && (
                        <span className="flex items-center gap-1 text-xs">
                          <Clock className="h-3 w-3" />
                          {t("token.neverExpire")}
                        </span>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <Switch
                      checked={token.enabled}
                      onCheckedChange={() => toggleMutation.mutate(token.id)}
                    />
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => setShowDelete(token.id)}
                    >
                      <Trash2 className="h-4 w-4 text-muted-foreground hover:text-destructive" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="logs" className="mt-4">
          {logs.length === 0 ? (
            <div className="flex flex-col items-center justify-center rounded-lg border border-dashed py-16">
              <p className="text-muted-foreground">{t("common.noData")}</p>
            </div>
          ) : (
            <div className="rounded-lg border">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="w-[120px]">{t("token.name")}</TableHead>
                    <TableHead className="w-[80px]">{t("token.method")}</TableHead>
                    <TableHead>{t("token.path")}</TableHead>
                    <TableHead>{t("token.requestBody")}</TableHead>
                    <TableHead className="w-[80px]">{t("token.responseCode")}</TableHead>
                    <TableHead className="w-[80px]">{t("token.duration")}</TableHead>
                    <TableHead className="w-[120px]">IP</TableHead>
                    <TableHead className="w-[160px]">{t("token.time")}</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {logs.map((log) => (
                    <TableRow key={log.id}>
                      <TableCell className="font-medium">{log.tokenName}</TableCell>
                      <TableCell>
                        <Badge variant="outline" className="font-mono text-xs">{log.requestMethod}</Badge>
                      </TableCell>
                      <TableCell className="max-w-[200px] truncate font-mono text-xs text-muted-foreground">
                        {log.requestPath}
                      </TableCell>
                      <TableCell className="max-w-[180px] truncate text-xs text-muted-foreground">
                        {log.requestBody}
                      </TableCell>
                      <TableCell>
                        <Badge
                          variant={log.responseCode === 200 ? "default" : "destructive"}
                          className="text-xs"
                        >
                          {log.responseCode}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-xs tabular-nums">{log.durationMs}ms</TableCell>
                      <TableCell className="font-mono text-xs text-muted-foreground">{log.clientIp}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">{formatDateTime(new Date(log.createdAt))}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* 创建 Token 对话框 */}
      <Dialog open={showCreate} onOpenChange={setShowCreate}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>{t("token.create")}</DialogTitle>
            <DialogDescription>{t("token.createDesc")}</DialogDescription>
          </DialogHeader>

          {createdToken ? (
            <div className="space-y-3">
              <div className="rounded-md border border-destructive/30 bg-destructive/5 p-3">
                <p className="text-sm font-medium text-destructive">{t("token.copyWarning")}</p>
              </div>
              <div className="flex items-center gap-2 rounded-md bg-muted p-3">
                <code className="flex-1 break-all text-sm font-medium">{createdToken}</code>
                <Button size="icon" variant="outline" onClick={() => handleCopy(createdToken)}>
                  <Copy className="h-4 w-4" />
                </Button>
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>{t("token.name")}</Label>
                <Input
                  value={newTokenName}
                  onChange={(e) => setNewTokenName(e.target.value)}
                  placeholder={t("token.namePlaceholder")}
                  onKeyDown={(e) => e.key === "Enter" && handleCreate()}
                />
              </div>
              <div className="space-y-2">
                <Label>{t("token.expiresAt")}</Label>
                <div className="flex flex-wrap gap-2">
                  {expiryOptions.map((opt) => (
                    <button
                      key={opt.value}
                      type="button"
                      onClick={() => setExpiryOption(opt.value)}
                      className={`rounded-md border px-3 py-1.5 text-sm transition-colors ${
                        expiryOption === opt.value
                          ? "border-primary bg-primary text-primary-foreground"
                          : "border-input bg-background hover:bg-accent hover:text-accent-foreground"
                      }`}
                    >
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}

          <DialogFooter>
            {createdToken ? (
              <Button onClick={() => setShowCreate(false)} className="w-full sm:w-auto">{t("common.confirm")}</Button>
            ) : (
              <>
                <Button variant="outline" onClick={() => setShowCreate(false)}>
                  {t("common.cancel")}
                </Button>
                <Button onClick={handleCreate} disabled={!newTokenName.trim() || createMutation.isPending}>
                  {t("common.confirm")}
                </Button>
              </>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* 删除确认 */}
      <Dialog open={showDelete != null} onOpenChange={() => setShowDelete(null)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>{t("token.confirmDelete")}</DialogTitle>
            <DialogDescription>{t("token.confirmDeleteDesc")}</DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDelete(null)}>
              {t("common.cancel")}
            </Button>
            <Button
              variant="destructive"
              onClick={() => showDelete && handleDelete(showDelete)}
              disabled={deleteMutation.isPending}
            >
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

