import { useState } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { ArrowLeft, Plus, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useWhitelist, useAddWhitelist, useRemoveWhitelist } from "@/hooks/use-admin-whitelist"
import type { User } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/whitelist")({
  component: WhitelistPage,
})

function WhitelistPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/whitelist" })
  const examId = Number(id)

  const { data: users, isLoading } = useWhitelist(examId)
  const addMutation = useAddWhitelist()
  const removeMutation = useRemoveWhitelist()

  const [inputValue, setInputValue] = useState("")
  const [removeTarget, setRemoveTarget] = useState<User | null>(null)

  const handleAdd = () => {
    const usernames = inputValue
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean)

    if (!usernames.length) {
      toast.error(t("admin.invalidUsernames"))
      return
    }

    addMutation.mutate(
      { examId, usernames },
      {
        onSuccess: () => {
          toast.success(t("admin.addWhitelistSuccess"))
          setInputValue("")
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleRemove = () => {
    if (!removeTarget) return
    removeMutation.mutate(
      { examId, userId: removeTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.removeWhitelistSuccess"))
          setRemoveTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <h1 className="text-xl font-semibold">{t("admin.whitelist")}</h1>
      </div>

      {/* 添加白名单 */}
      <div className="flex gap-2">
        <Input
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder={t("admin.whitelistInputPlaceholder")}
          className="max-w-md"
          onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleAdd())}
        />
        <Button onClick={handleAdd} disabled={addMutation.isPending}>
          <Plus className="h-4 w-4" />
          {t("admin.addUser")}
        </Button>
      </div>

      {/* 白名单列表 */}
      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !users?.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>{t("admin.username")}</TableHead>
              <TableHead>{t("admin.displayName")}</TableHead>
              <TableHead className="w-24 text-right">{t("common.actions")}</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {users.map((user) => (
              <TableRow key={user.id}>
                <TableCell>{user.username}</TableCell>
                <TableCell>{user.displayName}</TableCell>
                <TableCell>
                  <div className="flex justify-end">
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("admin.removeUser")}
                      onClick={() => setRemoveTarget(user)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {/* 移除确认弹窗 */}
      <Dialog open={!!removeTarget} onOpenChange={(open) => !open && setRemoveTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmRemove")}</DialogTitle>
            <DialogDescription>
              {t("admin.confirmRemoveWhitelistDesc", { name: removeTarget?.displayName })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setRemoveTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleRemove} disabled={removeMutation.isPending}>
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { get, post, del } from "@/lib/api"
import type { User } from "@/types"

const WHITELIST_KEY = "admin-whitelist"

/** 获取白名单用户列表 */
export function useWhitelist(examId: number) {
  return useQuery<User[]>({
    queryKey: [WHITELIST_KEY, examId],
    queryFn: () => get<User[]>(`/api/admin/exams/${examId}/whitelist`),
    enabled: examId > 0,
  })
}

/** 添加白名单用户（按用户名） */
export function useAddWhitelist() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ examId, usernames }: { examId: number; usernames: string[] }) =>
      post<void>(`/api/admin/exams/${examId}/whitelist`, { usernames }),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: [WHITELIST_KEY, variables.examId] })
    },
  })
}

/** 移除白名单用户 */
export function useRemoveWhitelist() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ examId, userId }: { examId: number; userId: number }) =>
      del<void>(`/api/admin/exams/${examId}/whitelist/${userId}`),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: [WHITELIST_KEY, variables.examId] })
    },
  })
}

