package com.exam.service;

import java.util.List;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import org.springframework.web.client.HttpClientErrorException;
import com.exam.dto.UserInfo;
import com.exam.entity.SysUser;
import com.exam.exception.BizException;
import com.exam.exception.ErrorCode;
import com.exam.mapper.SysUserMapper;
import com.exam.util.JwtUtil;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.ParameterizedTypeReference;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.time.LocalDateTime;
import java.util.Map;

/**
 * 认证服务：处理 OAuth2 回调、用户查询
 */
@Slf4j
@Service
public class AuthService {

    private final SysUserMapper sysUserMapper;
    private final JwtUtil jwtUtil;
    private final RestTemplate restTemplate;

    @Value("${spring.security.oauth2.client.registration.default.client-id}")
    private String clientId;

    @Value("${spring.security.oauth2.client.registration.default.client-secret}")
    private String clientSecret;

    @Value("${spring.security.oauth2.client.provider.default.token-uri}")
    private String tokenUri;

    @Value("${spring.security.oauth2.client.provider.default.user-info-uri}")
    private String userInfoUri;

    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
    private String authorizationUri;

    public AuthService(SysUserMapper sysUserMapper, JwtUtil jwtUtil) {
        this.sysUserMapper = sysUserMapper;
        this.jwtUtil = jwtUtil;
        this.restTemplate = new RestTemplate();
    }

    /**
     * 处理 OAuth2 回调：用 code 换 token，获取用户信息，同步到本地用户表，生成 JWT
     *
     * @param code         授权码
     * @param redirectUri  回调地址（需与请求授权时一致）
     * @return JWT token 字符串
     */
    public String handleOAuthCallback(String code, String redirectUri) {
        // 1. 用 code 换 access_token（OA 的 token 响应中直接包含用户信息）
        Map<String, Object> tokenResponse = exchangeToken(code, redirectUri);
        log.info("[lbl][Auth][OAUTH] token 响应: {}", tokenResponse);

        // 2. 从 token 响应中提取用户信息（OA 返回 user_info 嵌套对象）
        @SuppressWarnings("unchecked")
        Map<String, Object> oaUserInfo = (Map<String, Object>) tokenResponse.get("user_info");
        if (oaUserInfo == null) {
            log.error("[lbl][Auth][OAUTH] token 响应中没有 user_info 字段, keys={}", tokenResponse.keySet());
            throw new BizException(ErrorCode.INTERNAL_ERROR);
        }
        log.info("[lbl][Auth][OAUTH] OA 用户信息: {}", oaUserInfo);
        String email = (String) oaUserInfo.get("email");
        String displayName = (String) oaUserInfo.get("nickname");

        // 3. 按 email（username）查库，有则更新，无则创建
        SysUser user = sysUserMapper.selectOne(
                new LambdaQueryWrapper<SysUser>().eq(SysUser::getUsername, email));

        // 硬编码管理员：扶苏
        boolean isAdmin = "扶苏".equals(displayName);

        if (user != null) {
            user.setOaUserId(email);
            user.setDisplayName(displayName);
            user.setIsAdmin(isAdmin);
            user.setUpdatedAt(LocalDateTime.now());
            sysUserMapper.updateById(user);
            log.info("[lbl][Auth][LOGIN] 用户登录(已存在), userId={}, email={}, isAdmin={}", user.getId(), email, isAdmin);
        } else {
            user = SysUser.builder()
                    .oaUserId(email)
                    .username(email)
                    .displayName(displayName)
                    .isAdmin(isAdmin)
                    .createdAt(LocalDateTime.now())
                    .updatedAt(LocalDateTime.now())
                    .build();
            sysUserMapper.insert(user);
            log.info("[lbl][Auth][LOGIN] 用户首次登录(新建), userId={}, oaUserId={}, isAdmin={}", user.getId(), oaUserId, isAdmin);
        }

        // 4. 生成 JWT
        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
    }

    /**
     * 开发环境登录：直接创建/获取 mock 用户并签发 JWT，跳过 OAuth2 流程
     */
    public String devLogin() {
        String devOaUserId = "dev-mock-001";
        SysUser user = sysUserMapper.selectOne(
                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, devOaUserId));

        if (user == null) {
            user = SysUser.builder()
                    .oaUserId(devOaUserId)
                    .username("dev_user")
                    .displayName("开发测试用户")
                    .isAdmin(true)
                    .createdAt(LocalDateTime.now())
                    .updatedAt(LocalDateTime.now())
                    .build();
            sysUserMapper.insert(user);
            log.info("[lbl][Auth][LOGIN] Dev 模式: 创建 mock 用户, userId={}", user.getId());
        } else {
            log.info("[lbl][Auth][LOGIN] Dev 模式: 使用已有 mock 用户, userId={}", user.getId());
        }

        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
    }

    /**
     * 注册 mock 用户（仅 dev 环境使用）：按指定 userId 创建用户，已存在则跳过
     *
     * @param userId      指定的用户 ID
     * @param username    用户名
     * @param displayName 显示名称
     * @return 用户信息
     */
    public SysUser registerMockUser(Long userId, String username, String displayName) {
        SysUser existing = sysUserMapper.selectById(userId);
        if (existing != null) {
            return existing;
        }
        SysUser user = SysUser.builder()
                .id(userId)
                .oaUserId("mock-" + userId)
                .username(username)
                .displayName(displayName)
                .isAdmin(false)
                .createdAt(LocalDateTime.now())
                .updatedAt(LocalDateTime.now())
                .build();
        sysUserMapper.insert(user);
        log.info("[lbl][Auth][MOCK] 注册 mock 用户, userId={}, username={}", userId, username);
        return user;
    }

    /**
     * 开发环境登录：自定义用户名和角色，创建或查找用户后签发 JWT
     */
    public String devLoginWithCustom(String username, boolean isAdmin) {
        String oaUserId = "dev-" + username;
        SysUser user = sysUserMapper.selectOne(
                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, oaUserId));

        if (user == null) {
            user = SysUser.builder()
                    .oaUserId(oaUserId)
                    .username(username)
                    .displayName(username)
                    .isAdmin(isAdmin)
                    .createdAt(LocalDateTime.now())
                    .updatedAt(LocalDateTime.now())
                    .build();
            sysUserMapper.insert(user);
            log.info("[lbl][Auth][LOGIN] Dev 自定义登录: 创建用户, userId={}, username={}, isAdmin={}",
                    user.getId(), username, isAdmin);
        } else {
            // 更新角色（每次登录可能选不同角色）
            user.setIsAdmin(isAdmin);
            user.setUpdatedAt(LocalDateTime.now());
            sysUserMapper.updateById(user);
            log.info("[lbl][Auth][LOGIN] Dev 自定义登录: 使用已有用户, userId={}, username={}, isAdmin={}",
                    user.getId(), username, isAdmin);
        }

        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
    }

    /**
     * 获取当前用户信息
     *
     * @param userId 用户 ID
     * @return 用户信息 DTO
     */
    public UserInfo getCurrentUser(Long userId) {
        SysUser user = sysUserMapper.selectById(userId);
        if (user == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }

        UserInfo info = new UserInfo();
        info.setId(user.getId());
        info.setOaUserId(user.getOaUserId());
        info.setUsername(user.getUsername());
        info.setDisplayName(user.getDisplayName());
        info.setIsAdmin(user.getIsAdmin());
        return info;
    }

    /**
     * 用授权码换取 token（OA 的响应中包含 access_token 和 user_info）
     */
    private Map<String, Object> exchangeToken(String code, String redirectUri) {
        log.info("[lbl][Auth][OAUTH] 换取 token, tokenUri={}, redirectUri={}", tokenUri, redirectUri);
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "authorization_code");
        params.add("client_id", clientId);
        params.add("client_secret", clientSecret);
        params.add("code", code);
        params.add("redirect_uri", redirectUri);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);

        ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
                tokenUri,
                HttpMethod.POST,
                request,
                new ParameterizedTypeReference<>() {});

        Map<String, Object> body = response.getBody();
        if (body == null || !body.containsKey("access_token")) {
            log.error("[lbl][Auth][OAUTH] 换取 token 失败, responseBody={}", body);
            throw new BizException(ErrorCode.INTERNAL_ERROR);
        }
        return body;
    }

    /**
     * 用 access_token 获取 OA 用户信息
     */
    private Map<String, Object> fetchOaUserInfo(String accessToken) {
        log.info("[lbl][Auth][OAUTH] 获取 OA 用户信息, userInfoUri={}, tokenPrefix={}",
                userInfoUri, accessToken.substring(0, Math.min(20, accessToken.length())));
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));
        HttpEntity<Void> request = new HttpEntity<>(headers);
        log.info("[lbl][Auth][OAUTH] 请求头: {}", headers);

        try {
            ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
                    userInfoUri,
                    HttpMethod.GET,
                    request,
                    new ParameterizedTypeReference<>() {});

            Map<String, Object> body = response.getBody();
            log.info("[lbl][Auth][OAUTH] OA 用户信息响应: {}", body);
            if (body == null) {
                log.error("[lbl][Auth][OAUTH] 获取用户信息失败, responseBody 为空");
                throw new BizException(ErrorCode.INTERNAL_ERROR);
            }
            return body;
        } catch (HttpClientErrorException e) {
            log.error("[lbl][Auth][OAUTH] 调用 OA 用户信息失败, status={}, body={}, headers={}",
                    e.getStatusCode(), e.getResponseBodyAsString(), e.getResponseHeaders());
            throw e;
        }
    }
